module div_16bit (
    input [15:0] A,
    input [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);

    reg [15:0] a_reg, b_reg;
    reg [15:0] quotient, remainer;

    always @(A, B) begin
        a_reg = A;
        b_reg = B;
    end

    always @(a_reg, b_reg) begin
        quotient = 0;
        remainer = 0;

        for (int i = 15; i >= 0; i--) begin
            remainer = {remainer[14:0], a_reg[i]};
            if (remainer >= b_reg) begin
                remainer = remainer - b_reg;
                quotient[i] = 1'b1;
            end
        end

        result = quotient;
        odd = remainer;
    end

endmodule
